import React, {useEffect, useState, useRef} from 'react'
import styled from 'styled-components'
import Header from '../components/Header'
import Navbar from '../components/Navbar'
import Sidebar from '../components/Sidebar'
import ListingCard from '../components/ListingCard'
import {useSelector, useDispatch} from 'react-redux'
//import {shopSelector, getListing} from '../redux/shopSlice.js'
import {shopSelector, getFilter} from '../redux/shopSlice'

const ShopContentWrapper = styled.div `
width:80%;
margin:40px auto;
display:flex;

`

const SidebarWrapper = styled.div `
width:20%;
`

const Listings = styled.div `
width:80%;
display:flex;
flex-wrap: wrap;
justify-content: center;
`

export default function Shop () {
	const dispatch = useDispatch()
	const listSelector = useSelector(shopSelector)
	const [listing, setListing] = useState([])
	const [isSameCategoryFilter, setIsSameCategoryFilter] = useState({department:false, subCategory:false, size:false, designer:false, condition:false})

	useEffect(() => {
		(async () => {
			const result = await fetch('http://localhost:5001/shop')
			const data = await result.json()
			setListing(() => {
				let newListing = []
				data.forEach(data => newListing.push(data))
				return newListing
			})
		})();
	},[])

	const handleCheckboxChange = (e, target) => {
		let id = Object.entries(target)[0][1]
		dispatch(getFilter([e.target.value, id]))
		if (Object.keys(target)[0] === 'department') {
			setIsSameCategoryFilter({...isSameCategoryFilter, department:true})
			setListing(listing.filter(listing => listing.department_id === id))
			if (isSameCategoryFilter.department === true) {
				const list = listing.filter(listing => listing.department_id === id)
				setListing([...listing, ...list])
			}
		} else if (Object.keys(target)[0] === 'category') {
			setIsSameCategoryFilter({...isSameCategoryFilter, category:true})
			setListing(listing.filter(listing => listing.category_id === id))
		} else if (Object.keys(target)[0] === 'subCategory') {
			setIsSameCategoryFilter({...isSameCategoryFilter, subCategory:true})
			setListing(listing.filter(listing => listing.subCategory_id === id))
		} else if (Object.keys(target)[0] === 'designer') {
			setIsSameCategoryFilter({...isSameCategoryFilter, designer:true})
			setListing(listing.filter(listing => listing.designer_id === id))
		} else if (Object.keys(target)[0] === 'condition') {
			setIsSameCategoryFilter({...isSameCategoryFilter, condition:true})
			setListing(listing.filter(listing => listing.condition_id === id))
		}

	}

	return (
		<>
			<Header />
			<Navbar />
			<ShopContentWrapper>
				<SidebarWrapper>
					<Sidebar handleCheckboxChange={handleCheckboxChange}/>
				</SidebarWrapper>
				<Listings>
					{listing.map(listing => <ListingCard key={listing.id}>{listing}</ListingCard>)}
				</Listings>
			</ShopContentWrapper>
		</>
	)
}
